parameters.jsCode:
// 1. Get the string from the webhook body
const rawBody = $input.first().json.body;

// 2. Parse the string into a real Javascript Array
const emails = JSON.parse(rawBody);

// 3. Map the array into the format n8n expects (an array of objects with a 'json' key)
return emails.map(email => {
  return {
    json: email
  };
});

// Ensure "Mode" is set to "Run Once for Each Item" in the node parameters
const item = $input.item;
const rawFrom = $('Loop Over Items').item.json.From || ""; 
let llmText = item.json.text || "";
let llmResponse = {};

// 1. Clean the LLM string (removes markdown backticks if present)
llmText = llmText.replace(/```json|```/gi, "").trim();

// 2. Resilient JSON Parsing
try {
  llmResponse = JSON.parse(llmText);
} catch (e) {
  // Fallback: If parsing fails, try to extract JSON-like content using regex
  const jsonMatch = llmText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      llmResponse = JSON.parse(jsonMatch[0]);
    } catch (innerError) {
      llmResponse = { category: "Error", reasoning: "Regex extraction failed", draft_reply: null };
    }
  } else {
    llmResponse = { category: "Error", reasoning: "No JSON found in LLM output", draft_reply: null };
  }
}

// 3. Extract Name/Email & Set Timestamp
const nameMatch = rawFrom.match(/^([^<]+)/);
const cleanName = nameMatch ? nameMatch[1].trim() : "Influencer";
const emailMatch = rawFrom.match(/<([^>]+)>/);
const cleanEmail = emailMatch ? emailMatch[1] : rawFrom;
const processedAt = new Date().toLocaleString();

return {
  json: {
    ...item.json,
    ...llmResponse, 
    sender_name: cleanName,
    sender_email: cleanEmail,
    processed_at: processedAt
  }
};

